        _imageFile!.path,
        s3Key,
        AWS_S3_BUCKET_NAME,
        AWS_REGION, // The aws_s3_client requires region here too
        contentType: mimeType,
      );

      setState(() {
        _s3UploadStatus = 'Upload successful! Key: $s3Key';
        _isLoading = false;
      });
