  Future<void> _analyzeWithVision() async {
    if (_imageFile == null) {
      setState(() {
        _visionAnalysisResult = 'Please pick an image first.';
      });
      return;
    }

    setState(() {
      _isLoading = true;
      _visionAnalysisResult = 'Analyzing with Google Cloud Vision API...';
