            }
          }

          // Safe Search Detection
          if (firstResponse['safeSearchAnnotation'] != null) {
            resultBuffer.writeln('\nSafe Search:');
            final safeSearch = firstResponse['safeSearchAnnotation'];
            resultBuffer.writeln('Adult: ${safeSearch['adult']}');
            resultBuffer.writeln('Medical: ${safeSearch['medical']}');
            resultBuffer.writeln('Racy: ${safeSearch['racy']}');
            resultBuffer.writeln('Spoof: ${safeSearch['spoof']}');
            resultBuffer.writeln('Violence: ${safeSearch['violence']}');
          }

          // Text Detection
          if (firstResponse['textAnnotations'] != null && firstResponse['textAnnotations'].isNotEmpty) {
            resultBuffer.writeln('\nDetected Text:');
            resultBuffer.writeln(firstResponse['textAnnotations'][0]['description']); // Full text detected
          }

          if (resultBuffer.isEmpty) {
            resultBuffer.writeln('No specific annotations found.');
          }
        } else {
          resultBuffer.writeln('No responses from Vision API.');
        }

        setState(() {
          _visionAnalysisResult = resultBuffer.toString();
          _isLoading = false;
        });
      } else {
        setState(() {
          _visionAnalysisResult =
              'Vision API error: ${response.statusCode}\n${response.body}';
          _isLoading = false;
        });
        print('Vision API Error: ${response.statusCode}\n${response.body}');
      }
    } catch (e) {
      setState(() {
        _visionAnalysisResult = 'Vision API failed: $e';
        _isLoading = false;
      });
